// Gather inputs from all upstream nodes
const webhookData = $('Webhook - Receive Content Request').first().json.body;
const trendsData = $('HTTP - Query Notion Trends DB').first().json;
const performanceData = $('HTTP - Query Notion Performance DB').first().json;
const creatorData = $('HTTP - Query Creator Intelligence DB').first().json;

const userTopic = webhookData.topic || 'general content';
const platform = webhookData.platform || 'tiktok';
const style = webhookData.style || 'educational';

// Extract top trends
const trends = (trendsData.results || []).map(page => {
  const props = page.properties || {};
  return {
    name: props.Name?.title?.[0]?.plain_text || 'Unknown Trend',
    score: props.TrendScore?.number || 0,
    description: props.Description?.rich_text?.[0]?.plain_text || '',
    hashtags: props.Hashtags?.rich_text?.[0]?.plain_text || ''
  };
});

// Extract performance patterns
const patterns = (performanceData.results || []).map(page => {
  const props = page.properties || {};
  return {
    contentType: props.ContentType?.select?.name || 'Unknown',
    engagementRate: props.EngagementRate?.number || 0,
    avgViews: props.AvgViews?.number || 0,
    pattern: props.Pattern?.rich_text?.[0]?.plain_text || '',
    platform: props.Platform?.select?.name || 'All'
  };
});

// Extract winning hooks
const hooks = (creatorData.results || []).map(page => {
  const props = page.properties || {};
  return {
    hook: props.Hook?.title?.[0]?.plain_text || '',
    winRate: props.WinRate?.number || 0,
    template: props.Template?.rich_text?.[0]?.plain_text || ''
  };
});

// Build platform-specific guidance
const platformGuidance = {
  tiktok: 'TikTok: Hook in first 2 seconds, fast-paced edits, trending audio, 15-60 seconds optimal, vertical 9:16',
  youtube: 'YouTube Shorts: Hook in first 3 seconds, value-dense, strong CTA, 60 seconds max, vertical 9:16',
  instagram: 'Instagram Reels: Aesthetic visuals, hook in 3 seconds, trending audio, 15-30 seconds optimal, vertical 9:16',
  twitter: 'Twitter/X Video: Text-on-screen for silent viewing, hook in first frame, 30-60 seconds, landscape or square ok'
};

const styleGuidance = {
  educational: 'Educational: Teach one concrete thing. Use "Did you know", "Stop doing X", "The secret to X" hooks.',
  entertaining: 'Entertaining: Make them laugh or feel something. Use relatable situations, unexpected twists.',
  motivational: 'Motivational: Inspire action. Use transformation stories, before/after, "You can do this" energy.',
  storytelling: 'Storytelling: Personal narrative arc. Hook with conflict, resolve with lesson.'
};

const systemPrompt = `You are a world-class viral content strategist and scriptwriter who has helped creators grow from 0 to millions of followers. You deeply understand the psychology of attention, the mechanics of algorithms, and what makes content shareable.

You specialize in ${platform} content that is ${style}. You understand platform-specific best practices, trending formats, and audience psychology.

You ALWAYS respond with valid JSON only. No markdown, no explanations outside the JSON structure.`;

const userMessage = `Create a complete viral content plan for this topic: "${userTopic}"

Platform: ${platform}
Style: ${style}
Platform Guidance: ${platformGuidance[platform] || platformGuidance.tiktok}
Style Guidance: ${styleGuidance[style] || styleGuidance.educational}

CURRENT TRENDING TOPICS (use these for relevance):
${JSON.stringify(trends, null, 2)}

TOP PERFORMING CONTENT PATTERNS (replicate what works):
${JSON.stringify(patterns.slice(0, 5), null, 2)}

WINNING HOOK TEMPLATES (adapt these proven hooks):
${JSON.stringify(hooks.slice(0, 5), null, 2)}

Generate a complete content plan as JSON with this EXACT structure:
{
  "videoIdeas": [
    {
      "ideaNumber": 1,
      "title": "Video title",
      "hook": "Opening hook line (first 2-3 seconds)",
      "angle": "Unique angle or perspective",
      "viralMechanism": "Why this will go viral",
      "estimatedViews": "View range estimate"
    }
  ],
  "featuredScript": {
    "ideaNumber": 1,
    "hook": "Exact opening words",
    "intro": "Seconds 0-10 script",
    "mainContent": "Seconds 10-50 script",
    "conclusion": "Seconds 50-60 script",
    "totalDuration": "60 seconds",
    "toneNotes": "Delivery notes"
  },
  "captions": {
    "tiktok": "TikTok caption with emoji and hashtags",
    "youtube": "YouTube Shorts caption with hashtags",
    "instagram": "Instagram Reels caption with emoji and hashtags"
  },
  "hashtags": {
    "primary": ["list", "of", "5", "primary", "hashtags"],
    "secondary": ["list", "of", "10", "secondary", "hashtags"],
    "niche": ["list", "of", "5", "niche", "hashtags"]
  },
  "thumbnailConcept": {
    "visualDescription": "What the thumbnail looks like",
    "textOverlay": "Bold text on thumbnail",
    "colorScheme": "Color palette",
    "faceExpression": "Emotion/expression if applicable"
  },
  "brollSuggestions": [
    "B-roll shot 1 description",
    "B-roll shot 2 description",
    "B-roll shot 3 description",
    "B-roll shot 4 description",
    "B-roll shot 5 description"
  ],
  "callToActionOptions": [
    "CTA option 1",
    "CTA option 2",
    "CTA option 3"
  ],
  "bestPostingTime": "Recommended posting time window",
  "trendAlignment": "Which current trend this aligns with"
}`;

return [{
  json: {
    systemPrompt,
    userMessage,
    userTopic,
    platform,
    style,
    trendsUsed: trends.length,
    patternsUsed: patterns.length,
    hooksUsed: hooks.length
  }
}];

const claudeResponse = $input.first().json;
const codeOutput = $('Code - Assemble Rich Context Prompt').first().json;

// Extract the text content from Claude's response
let rawContent = '';
try {
  rawContent = claudeResponse.content?.[0]?.text || '';
} catch (e) {
  throw new Error('Failed to extract Claude response text: ' + e.message);
}

// Parse JSON from Claude's response
let contentPlan;
try {
  // Try direct parse first
  contentPlan = JSON.parse(rawContent);
} catch (e) {
  // Try extracting JSON from markdown code block if present
  const jsonMatch = rawContent.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    try {
      contentPlan = JSON.parse(jsonMatch[1]);
    } catch (e2) {
      throw new Error('Failed to parse Claude JSON response: ' + rawContent.substring(0, 500));
    }
  } else {
    throw new Error('No valid JSON found in Claude response: ' + rawContent.substring(0, 500));
  }
}

// Build the featured idea title
const featuredIdea = contentPlan.videoIdeas?.[contentPlan.featuredScript?.ideaNumber - 1] 
  || contentPlan.videoIdeas?.[0] 
  || {};

// Flatten hashtags for Notion
const allHashtags = [
  ...(contentPlan.hashtags?.primary || []),
  ...(contentPlan.hashtags?.secondary || []),
  ...(contentPlan.hashtags?.niche || [])
].join(' ');

// Build captions text
const captionBlock = [
  `=== TikTok ===\n${contentPlan.captions?.tiktok || ''}`,
  `\n=== YouTube ===\n${contentPlan.captions?.youtube || ''}`,
  `\n=== Instagram ===\n${contentPlan.captions?.instagram || ''}`
].join('');

// Build B-roll text
const brollText = (contentPlan.brollSuggestions || []).join('\n• ');

// Build full script
const fullScript = contentPlan.featuredScript ? [
  `HOOK: ${contentPlan.featuredScript.hook || ''}`,
  `INTRO (0-10s): ${contentPlan.featuredScript.intro || ''}`,
  `MAIN (10-50s): ${contentPlan.featuredScript.mainContent || ''}`,
  `CLOSE (50-60s): ${contentPlan.featuredScript.conclusion || ''}`,
  `TONE: ${contentPlan.featuredScript.toneNotes || ''}`
].join('\n\n') : '';

const now = new Date().toISOString();

return [{
  json: {
    contentPlan,
    notionPayload: {
      ideaTitle: featuredIdea.title || codeOutput.userTopic,
      hook: featuredIdea.hook || '',
      fullScript,
      captions: captionBlock,
      hashtags: allHashtags,
      thumbnailConcept: JSON.stringify(contentPlan.thumbnailConcept || {}),
      brollSuggestions: '• ' + brollText,
      callToActions: (contentPlan.callToActionOptions || []).join('\n'),
      platform: codeOutput.platform,
      style: codeOutput.style,
      topic: codeOutput.userTopic,
      trendAlignment: contentPlan.trendAlignment || '',
      generatedAt: now
    },
    // Pass full plan for webhook response
    responsePayload: {
      success: true,
      contentPlan,
      savedAt: now,
      platform: codeOutput.platform,
      topic: codeOutput.userTopic
    }
  }
}];
